// components/particles/LogisticsParticles.jsx
import { useEffect, useState } from "react";
import Particles, { initParticlesEngine } from "@tsparticles/react";
import { loadSlim } from "tsparticles-slim";

export default function LogisticsParticles() {
  const [init, setInit] = useState(false);

  useEffect(() => {
    initParticlesEngine(async (engine) => {
      await loadSlim(engine);
    }).then(() => {
      setInit(true);
    });
  }, []);

  const options = {
    fullScreen: { enable: false },
    background: { color: "transparent" },
    fpsLimit: 60,

    particles: {
      number: {
        value: 90,
        density: { enable: true, area: 900 },
      },
      color: {
        value: ["#7ddf64", "#34d399", "#6ee7b7", "#bbf7d0"],
      },
      // ТОЛЬКО "circle" — "triangle" вызывает баг drawer.validTypes в tsparticles-slim
      shape: { type: "circle" },

      opacity: {
        value: { min: 0.2, max: 0.8 },
        animation: { enable: true, speed: 0.8, sync: false },
      },
      size: {
        value: { min: 2, max: 6 },
      },
      // "Дороги" — сеть линий между частицами-машинами
      links: {
        enable: true,
        distance: 160,
        color: "#7ddf64",
        opacity: 0.3,
        width: 1.2,
      },
      move: {
        enable: true,
        speed: { min: 0.8, max: 3 },
        direction: "none",
        random: true,
        straight: false,
        outModes: { default: "out" },
      },
    },

    interactivity: {
      events: {
        onHover: { enable: true, mode: "grab" },
        onClick: { enable: true, mode: "push" },
      },
      modes: {
        grab: { distance: 160, links: { opacity: 0.7 } },
        push: { quantity: 3 },
      },
    },

    detectRetina: true,
  };

  if (!init) return null;

  return (
    <Particles
      id="logistics-particles"
      options={options}
      style={{
        position: "absolute",
        inset: 0,
        width: "100%",
        height: "100%",
        zIndex: 0,
      }}
    />
  );
}
